mapper.select:
select * from nx_customer_promotion_code
where owner_type = #{ownerType}
  and owner_id = #{ownerId}
  and code_status = 'ACTIVE'
order by created_at desc
limit 1

select * from nx_customer_promotion_code
where owner_type = #{ownerType}
  and owner_id = #{ownerId}
order by field(code_status, 'ACTIVE', 'SUSPENDED', 'DISABLED'), created_at desc
limit 1



    and c.owner_type = #{ownerType}
    and c.owner_id = #{ownerId}
    and c.community_id = #{communityId}
    and c.commerce_id = #{commerceId}
    and c.code_status = #{codeStatus}

        and c.promotion_code like concat('%', #{promotionCode}, '%')


        and (
            (c.owner_type = 'EXTERNAL_PROMOTER' and p.promoter_name like concat('%', #{ownerName}, '%'))
            or (c.owner_type = 'CUSTOMER_USER' and cu.nx_CU_wx_nick_name like concat('%', #{ownerName}, '%'))
            or (c.owner_type = 'COMMUNITY_USER' and cou.nx_COU_wx_nick_name like concat('%', #{ownerName}, '%'))
        )


order by c.created_at desc
limit #{offset}, #{limit}

mapper.update:
update nx_customer_promotion_code
code_status = #{codeStatus}, valid_start_at = #{validStartAt}, valid_end_at = #{validEndAt}, disabled_at = #{disabledAt}, disabled_reason = #{disabledReason},
where nx_customer_promotion_code_id = #{nxCustomerPromotionCodeId}

update nx_customer_promotion_code
set code_status = 'DISABLED',
    disabled_at = #{disabledAt},
    disabled_reason = #{disabledReason}
where owner_type = #{ownerType}
  and owner_id = #{ownerId}
  and code_status = 'ACTIVE'

mapper.select:
select count(*) from nx_customer_promotion_code
where owner_type = #{ownerType}
  and owner_id = #{ownerId}
  and code_status = 'ACTIVE'

